from flask import Flask, request, render_template, redirect, url_for, session, flash
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import qrcode
import io
import base64
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Mock user database
users = {
    "admin": {
        "password": generate_password_hash("password123"),
        "totp_secret": "JBSWY3DPEHPK3PXP"
    }
}

# Mock protected resources
protected_resources = {
    "dashboard": "Welcome to dashboard",
    "profile": "User profile information",
    "settings": "Account settings"
}

@app.route('/')
def index():
    if 'user_id' in session:
        return redirect(url_for('dashboard'))
    return redirect(url_for('login'))

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        
        if username in users and check_password_hash(users[username]['password'], password):
            session['user_id'] = username
            session['mfa_verified'] = False
            return redirect(url_for('verify_mfa'))
        else:
            flash('Invalid username or password')
    
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    
    if session.get('mfa_verified'):
        return redirect(url_for('dashboard'))
    
    if request.method == 'POST':
        otp = request.form['otp']
        user = users[session['user_id']]
        
        totp = pyotp.TOTP(user['totp_secret'])
        if totp.verify(otp, valid_window=2):
            session['mfa_verified'] = True
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid verification code')
    
    # Generate QR code for MFA setup
    totp_secret = users[session['user_id']]['totp_secret']
    totp_uri = pyotp.totp.TOTP(totp_secret).provisioning_uri(
        session['user_id'], issuer_name="MyApp"
    )
    
    qr = qrcode.QRCode(version=1, box_size=10, border=4)
    qr.add_data(totp_uri)
    qr.make(fit=True)
    
    img = qr.make_image(fill_color="black", back_color="white")
    img_buffer = io.BytesIO()
    img.save(img_buffer)
    img_buffer.seek(0)
    
    qr_code = base64.b64encode(img_buffer.getvalue()).decode()
    
    return render_template('verify_mfa.html', qr_code=qr_code)

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session or not session.get('mfa_verified'):
        return redirect(url_for('login'))
    return render_template('dashboard.html', user=session['user_id'])

@app.route('/profile')
def profile():
    if 'user_id' not in session or not session.get('mfa_verified'):
        return redirect(url_for('login'))
    return render_template('profile.html', content=protected_resources['profile'])

@app.route('/settings')
def settings():
    if 'user_id' not in session or not session.get('mfa_verified'):
        return redirect(url_for('login'))
    return render_template('settings.html', content=protected_resources['settings'])

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

if __name__ == '__main__':
    app.run(debug=True)